VALUES
  ('social-worker-moex-08040', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者並不符合「性別歧視之禁止」的原則？', '["雇主對求職者或受僱者之招募、甄試、進用、分發等，不得因性別或性傾向而有差別待遇。但工作性 質僅適合特定性別者，不在此限", "雇主對受僱者薪資之給付，不得因性別或性傾向而有差別待遇。但基於年資、獎懲、績效因素之正當 理由者，不在此限", "受僱者有結婚、懷孕、分娩或育兒之情事時，雇主不得以其為解僱之理由，但工作規則、勞動契約或 團體協約有事先約定者，不在此限", "雇主為受僱者舉辦或提供教育、訓練或其他類似活動，不得因性別或性傾向而有差別待遇"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08041', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據老人福利法，下列何者不屬於老人經濟安全保障逐步規劃實施之項目？', '["年金保險制度", "生活津貼", "三節禮金", "特別照顧津貼"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08042', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據兒童及少年福利法，滿幾歲之兒童及少年被收養時，兒童及少年之意願應受尊重？', '["6歲", "7歲", "10歲", "12歲"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08043', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據兒童及少年福利法，政府應規劃實施未滿幾歲之兒童及少年之醫療照顧措施，必要時並得視其家庭 經濟條件補助其費用？', '["6歲", "10歲", "12歲", "18歲"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08044', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據身心障礙者權益保障法，身心障礙者對障礙鑑定及需求評估有異議者，可以書面向直轄市、縣（市） 主管機關提出申請重新鑑定及需求評估，並以幾次為限？', '["一次", "兩次", "三次", "四次"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08045', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據家庭暴力防治法，法院核發下列何種保護令時，得不經審理程序？', '["暫時保護令或緊急保護令", "短期保護令或特別保護令", "通常保護令或長期保護令", "通常保護令或特別保護令"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08046', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據精神衛生法，嚴重病人依相關規定接受強制社區治療之費用，其不屬全民健康保險給付範圍者，由 下列何者負擔？', '["病人家屬", "地方主管機關", "中央主管機關", "中央主管機關、病人家屬及地方主管機關共同負擔"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08047', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '認為社會政策與立法，其實無法完全理性，而是根據先前施政的經驗逐步修正的，是下列那一種模型的 主張？', '["漸進模型", "制度學派模型", "公共選擇模型", "政策過程模型"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08048', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會福利政策綱領，不包括下列何項描述？', '["社會津貼應針對社會保險未涵蓋之給付項目，因國民特殊的需求而設計，非以所得高低作為發放與否 的根據", "因應勞動市場彈性化的趨勢，政府應保障各類勞工之勞動基準", "建立照顧管理機制，整合各類服務與資源，確保服務提供的效率與效益", "政府應建構以社區為基礎的心理衛生服務系統，推動分級預防工作"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08049', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '馬歇爾（Thomas Humphrey Marshall）所謂公民資格（Citizenship）的發展，不包括以下何種權利？', '["公民權（Civil rights）", "政治權（Political rights）", "社會權（Social rights）", "統治權（Governance rights）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
